101	    URL.revokeObjectURL(url);
102	  };
103	
104	  const formatFileSize = (bytes: number | null) => {
105	    if (!bytes) return "";
106	    if (bytes < 1024) return bytes + " B";
107	    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
108	    return (bytes / (1024 * 1024)).toFixed(1) + " MB";
109	  };
110	
111	  // Group items by month
112	  const groupByMonth = <T extends { created_at: string }>(items: T[]) => {
113	    const groups: { label: string; items: T[] }[] = [];
114	    let currentLabel = "";
115	    items.forEach((item) => {
116	      const label = format(new Date(item.created_at), "MMMM yyyy").toUpperCase();
117	      if (label !== currentLabel) {
118	        currentLabel = label;
