import { useCallback, useRef, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
  initUserKeys,
  getUserPrivateKey,
  generateRoomKey,
  wrapRoomKey,
  unwrapRoomKey,
  encryptMessage,
  decryptMessage,
  cacheRoomKey,
  getCachedRoomKey,
  clearRoomKeyCache,
  isEncryptedContent,
  restorePrivateKeyV1,
  isV2Key,
} from "@/lib/e2e-crypto";

export function useE2EEncryption(currentUserId: string) {
  const [e2eReady, setE2eReady] = useState(false);
  const publicKeyRef = useRef<JsonWebKey | null>(null);
  const initPromiseRef = useRef<Promise<void> | null>(null);

  // Initialises local (IDB) key state for the current user.
  // Supabase sync is owned by useInitializeE2EE in App.tsx — this hook must not
  // write to user_encryption_keys or it will race against the app-level init and
  // risk overwriting a correctly backed-up key pair with a freshly generated one.
  const initEncryption = useCallback(async () => {
    if (!currentUserId || initPromiseRef.current) return;

    initPromiseRef.current = (async () => {
      try {
        const { publicKeyJwk } = await initUserKeys(currentUserId);
        publicKeyRef.current = publicKeyJwk;
        setE2eReady(true);
      } catch (err) {
        console.error("E2EE init failed:", err);
        // Privacy by Default: do NOT set e2eReady on failure.
        // The send path will throw before writing an unencrypted message.
      }
    })();

    await initPromiseRef.current;
  }, [currentUserId]);

  // Gets the user's private key from IndexedDB, falling back to the encrypted Supabase backup.
  // This is the cross-device fix: new devices decrypt the backup and cache locally.
  const getOrRestorePrivateKey = useCallback(async (): Promise<CryptoKey | null> => {
    const cached = await getUserPrivateKey(currentUserId);
    if (cached) return cached;

    const { data } = await supabase
      .from("user_encryption_keys")
      .select("encrypted_private_key, key_salt")
      .eq("user_id", currentUserId)
      .maybeSingle();

    if (!data?.encrypted_private_key || !data?.key_salt) return null;

    // v2 keys require a recovery password that this hook doesn't have access to.
    // useInitializeE2EE in App.tsx owns that restore flow. If we land here with a
    // v2 key, the user hasn't completed recovery yet — return null so the send path
    // fails loudly rather than silently dropping their message.
    if (isV2Key(data.encrypted_private_key)) {
      console.warn("getOrRestorePrivateKey: v2 key requires recovery password — use useInitializeE2EE");
      return null;
    }

    try {
      return await restorePrivateKeyV1(currentUserId, data.encrypted_private_key, data.key_salt);
    } catch (err) {
      console.error("Failed to restore private key from backup:", err);
      return null;
    }
  }, [currentUserId]);

  const getPublicKey = useCallback(async (userId: string): Promise<JsonWebKey | null> => {
    const { data } = await supabase
      .from("user_encryption_keys")
      .select("public_key")
      .eq("user_id", userId)
      .maybeSingle();

    if (data?.public_key) {
      return JSON.parse(data.public_key);
    }
    return null;
  }, []);

  const setupRoomEncryption = useCallback(async (roomId: string, memberUserIds: string[]) => {
    if (!currentUserId) return;

    const privateKey = await getOrRestorePrivateKey();
    if (!privateKey) return;

    const roomKey = await generateRoomKey();
    await cacheRoomKey(roomId, roomKey);

    for (const memberId of memberUserIds) {
      const memberPublicKey = await getPublicKey(memberId);
      if (!memberPublicKey) continue;

      try {
        const encryptedKey = await wrapRoomKey(roomKey, privateKey, memberPublicKey);
        await supabase.from("room_encrypted_keys" as any).upsert(
          {
            room_id: roomId,
            user_id: memberId,
            encrypted_by: currentUserId,
            encrypted_key: encryptedKey,
          },
          { onConflict: "room_id,user_id" }
        );
      } catch (err) {
        console.error(`Failed to wrap key for ${memberId}:`, err);
      }
    }
  }, [currentUserId, getPublicKey, getOrRestorePrivateKey]);

  const getRoomKey = useCallback(async (roomId: string): Promise<CryptoKey | null> => {
    const cached = await getCachedRoomKey(roomId);
    if (cached) return cached;

    if (!currentUserId) return null;
    const privateKey = await getOrRestorePrivateKey();
    if (!privateKey) return null;

    const { data: keyRecord } = await supabase
      .from("room_encrypted_keys" as any)
      .select("encrypted_key, encrypted_by")
      .eq("room_id", roomId)
      .eq("user_id", currentUserId)
      .maybeSingle() as any;

    if (!keyRecord?.encrypted_key) return null;

    const encryptorPublicKey = await getPublicKey(keyRecord.encrypted_by);
    if (!encryptorPublicKey) return null;

    try {
      const roomKey = await unwrapRoomKey(
        keyRecord.encrypted_key,
        privateKey,
        encryptorPublicKey
      );
      await cacheRoomKey(roomId, roomKey);
      return roomKey;
    } catch (err) {
      console.warn("Failed to unwrap room key:", err);
      return null;
    }
  }, [currentUserId, getPublicKey, getOrRestorePrivateKey]);

  const encrypt = useCallback(async (plaintext: string, roomId: string): Promise<string | null> => {
    const roomKey = await getRoomKey(roomId);
    if (!roomKey) return null;
    return encryptMessage(plaintext, roomKey);
  }, [getRoomKey]);

  const decrypt = useCallback(async (ciphertext: string, roomId: string): Promise<string> => {
    if (!isEncryptedContent(ciphertext)) return ciphertext;
    const roomKey = await getRoomKey(roomId);
    if (!roomKey) return "🔒 Encrypted message";
    const result = await decryptMessage(ciphertext, roomKey);
    if (result === "[Unable to decrypt message]") {
      await clearRoomKeyCache(roomId);
      const freshKey = await getRoomKey(roomId);
      if (!freshKey) return "🔒 Encrypted message";
      const retry = await decryptMessage(ciphertext, freshKey);
      return retry === "[Unable to decrypt message]" ? "🔒 Encrypted message" : retry;
    }
    return result;
  }, [getRoomKey]);

  const decryptMessages = useCallback(async (
    messages: Array<{ content: string | null; room_id: string; is_encrypted: boolean; [key: string]: any }>
  ) => {
    const roomKeys = new Map<string, CryptoKey | null>();

    return Promise.all(
      messages.map(async (msg) => {
        if (!msg.content) return msg;

        // Privacy by Default: never render unencrypted text message content.
        // Non-text types (file, voice, invoice) store metadata only — allow through.
        if (!msg.is_encrypted) {
          if (msg.message_type === "text" || !msg.message_type) {
            return { ...msg, content: "🔒 [Sent before encryption]" };
          }
          return msg;
        }

        let roomKey = roomKeys.get(msg.room_id);
        if (roomKey === undefined) {
          roomKey = await getRoomKey(msg.room_id);
          roomKeys.set(msg.room_id, roomKey);
        }

        if (!roomKey) {
          return {
            ...msg,
            content: isEncryptedContent(msg.content) ? "[Encryption key unavailable]" : msg.content,
          };
        }

        if (isEncryptedContent(msg.content)) {
          let decrypted = await decryptMessage(msg.content, roomKey);
          if (decrypted === "[Unable to decrypt message]") {
            await clearRoomKeyCache(msg.room_id);
            const freshKey = await getRoomKey(msg.room_id);
            if (freshKey) {
              const retry = await decryptMessage(msg.content, freshKey);
              decrypted = retry === "[Unable to decrypt message]" ? "🔒 Encrypted message" : retry;
              roomKeys.set(msg.room_id, freshKey);
            } else {
              decrypted = "🔒 Encrypted message";
            }
          }
          return { ...msg, content: decrypted };
        }
        return msg;
      })
    );
  }, [getRoomKey]);

  // Redistributes the EXISTING room key to all members without generating a new one.
  // Call this when a member can't decrypt — the person who HAS the key runs this.
  const redistributeRoomKey = useCallback(async (roomId: string, memberUserIds: string[]): Promise<boolean> => {
    if (!currentUserId) return false;
    const roomKey = await getRoomKey(roomId);
    if (!roomKey) return false; // caller doesn't have the key — can't redistribute

    const privateKey = await getOrRestorePrivateKey();
    if (!privateKey) return false;

    for (const memberId of memberUserIds) {
      const memberPublicKey = await getPublicKey(memberId);
      if (!memberPublicKey) continue;
      try {
        const encryptedKey = await wrapRoomKey(roomKey, privateKey, memberPublicKey);
        await supabase.from("room_encrypted_keys" as any).upsert(
          { room_id: roomId, user_id: memberId, encrypted_by: currentUserId, encrypted_key: encryptedKey },
          { onConflict: "room_id,user_id", ignoreDuplicates: true }
        );
      } catch (err) {
        console.error(`Failed to redistribute key for ${memberId}:`, err);
      }
    }
    return true;
  }, [currentUserId, getRoomKey, getOrRestorePrivateKey, getPublicKey]);

  return {
    e2eReady,
    initEncryption,
    setupRoomEncryption,
    redistributeRoomKey,
    encrypt,
    decrypt,
    decryptMessages,
    getRoomKey,
    getPublicKey,
  };
}

import { useState, useEffect, useMemo } from "react";
import { supabase } from "@/integrations/supabase/client";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Download, File, Image as ImageIcon, Link2, FileSignature, Receipt, ExternalLink, Video, Play } from "lucide-react";
import { format } from "date-fns";
import { toast } from "sonner";

interface MediaMessage {
  id: string;
  content: string | null;
  message_type: string;
  file_url: string | null;
  file_name: string | null;
  file_type: string | null;
  file_size: number | null;
  invoice_id: string | null;
  contract_id: string | null;
  created_at: string;
}

interface ChatMediaPanelProps {
  roomId: string;
}

type TabType = "media" | "docs" | "links";

const ChatMediaPanel = ({ roomId }: ChatMediaPanelProps) => {
  const [activeTab, setActiveTab] = useState<TabType>("media");
  const [allMessages, setAllMessages] = useState<MediaMessage[]>([]);
  const [loading, setLoading] = useState(true);
  const [signedUrls, setSignedUrls] = useState<Record<string, string>>({});

  useEffect(() => {
    const fetchMedia = async () => {
      setLoading(true);
      const { data } = await supabase
        .from("chat_messages")
        .select("id, content, message_type, file_url, file_name, file_type, file_size, invoice_id, contract_id, created_at")
        .eq("room_id", roomId)
        .in("message_type", ["file", "invoice", "contract", "text"])
        .order("created_at", { ascending: false });

      setAllMessages(data || []);
      setLoading(false);
    };
    fetchMedia();
  }, [roomId]);

  // Fetch signed URLs for all image/video attachments so thumbnails actually render
  useEffect(() => {
    if (allMessages.length === 0) return;

    const mediaMsgs = allMessages.filter(
      (m) =>
        m.message_type === "file" &&
        (m.file_type?.startsWith("image/") || m.file_type?.startsWith("video/")) &&
        m.file_url &&
        !m.file_url.startsWith("http")
    );

    if (mediaMsgs.length === 0) return;

    Promise.all(
      mediaMsgs.map(async (m) => {
        const { data } = await supabase.storage
          .from("chat-files")
          .createSignedUrl(m.file_url!, 3600);
        return data?.signedUrl ? { path: m.file_url!, url: data.signedUrl } : null;
      })
    ).then((results) => {
      const map: Record<string, string> = {};
      results.forEach((r) => { if (r) map[r.path] = r.url; });
      setSignedUrls(map);
    });
  }, [allMessages]);

  const getUrl = (fileUrl: string) => {
    if (fileUrl.startsWith("http")) return fileUrl;
    return signedUrls[fileUrl] ?? "";
  };

  const urlRegex = /(https?:\/\/[^\s]+)/g;

  // Media = images + videos
  const mediaItems = useMemo(
    () =>
      allMessages.filter(
        (m) =>
          m.message_type === "file" &&
          (m.file_type?.startsWith("image/") || m.file_type?.startsWith("video/"))
      ),
    [allMessages]
  );

  // Docs = non-image/non-video files + invoices + contracts
  const docItems = useMemo(
    () =>
      allMessages.filter(
        (m) =>
          (m.message_type === "file" &&
            !m.file_type?.startsWith("image/") &&
            !m.file_type?.startsWith("video/")) ||
          m.message_type === "invoice" ||
          m.message_type === "contract"
      ),
    [allMessages]
  );

  const linkItems = useMemo(() => {
    const links: { id: string; url: string; created_at: string }[] = [];
    allMessages.forEach((m) => {
      if (m.content) {
        const matches = m.content.match(urlRegex);
        if (matches) {
          matches.forEach((url) => links.push({ id: m.id + url, url, created_at: m.created_at }));
        }
      }
    });
    return links;
  }, [allMessages]);

  const tabs: { id: TabType; label: string; count: number }[] = [
    { id: "media", label: "Media", count: mediaItems.length },
    { id: "docs", label: "Docs", count: docItems.length },
    { id: "links", label: "Links", count: linkItems.length },
  ];

  const downloadFile = async (fileUrl: string, fileName: string) => {
    if (fileUrl.startsWith("http")) {
      const a = document.createElement("a");
      a.href = fileUrl;
      a.download = fileName;
      a.target = "_blank";
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      return;
    }
    const { data, error } = await supabase.storage.from("chat-files").download(fileUrl);
    if (error) {
      toast.error("Download failed");
      return;
    }
    const url = URL.createObjectURL(data);
    const a = document.createElement("a");
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const formatFileSize = (bytes: number | null) => {
    if (!bytes) return "";
    if (bytes < 1024) return bytes + " B";
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
    return (bytes / (1024 * 1024)).toFixed(1) + " MB";
  };

  const groupByMonth = <T extends { created_at: string }>(items: T[]) => {
    const groups: { label: string; items: T[] }[] = [];
    let currentLabel = "";
    items.forEach((item) => {
      const label = format(new Date(item.created_at), "MMMM yyyy").toUpperCase();
      if (label !== currentLabel) {
        currentLabel = label;
        groups.push({ label, items: [item] });
      } else {
        groups[groups.length - 1].items.push(item);
      }
    });
    return groups;
  };

  return (
    <div className="mt-2">
      {/* Tabs */}
      <div className="flex border-b border-border relative">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 py-2.5 text-xs font-semibold tracking-wider uppercase text-center transition-colors relative ${
              activeTab === tab.id ? "text-bronze" : "text-muted-foreground hover:text-foreground"
            }`}
          >
            {tab.label}
            {tab.count > 0 && (
              <span className="ml-1 text-[10px] opacity-60">{tab.count}</span>
            )}
            {activeTab === tab.id && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-bronze rounded-full" />
            )}
          </button>
        ))}
      </div>

      {/* Content */}
      <ScrollArea className="h-[260px] mt-2">
        {loading ? (
          <div className="flex items-center justify-center h-full text-muted-foreground text-sm py-8">
            Loading...
          </div>
        ) : (
          <>
            {/* Media Tab — images + videos */}
            {activeTab === "media" && (
              mediaItems.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
                  <ImageIcon className="h-8 w-8 mb-2 opacity-30" />
                  <p className="text-xs">No media shared yet</p>
                </div>
              ) : (
                <div className="space-y-3 px-1">
                  {groupByMonth(mediaItems).map((group) => (
                    <div key={group.label}>
                      <p className="text-[10px] font-bold text-muted-foreground tracking-wider mb-2">
                        {group.label}
                      </p>
                      <div className="grid grid-cols-3 gap-1.5">
                        {group.items.map((item) => {
                          const isVideo = item.file_type?.startsWith("video/");
                          const url = item.file_url ? getUrl(item.file_url) : "";
                          return (
                            <button
                              key={item.id}
                              onClick={() => item.file_url && downloadFile(item.file_url, item.file_name || (isVideo ? "video" : "image"))}
                              className="aspect-square rounded-lg bg-muted overflow-hidden hover:opacity-80 transition-opacity relative group"
                            >
                              {url ? (
                                isVideo ? (
                                  <>
                                    <video
                                      src={url}
                                      className="w-full h-full object-cover"
                                      preload="metadata"
                                      muted
                                    />
                                    {/* Play overlay */}
                                    <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                                      <div className="h-7 w-7 rounded-full bg-black/50 flex items-center justify-center">
                                        <Play className="h-3.5 w-3.5 text-white fill-white ml-0.5" />
                                      </div>
                                    </div>
                                  </>
                                ) : (
                                  <img
                                    src={url}
                                    alt={item.file_name || "image"}
                                    className="w-full h-full object-cover"
                                    loading="lazy"
                                  />
                                )
                              ) : (
                                /* Loading skeleton while signed URL is being fetched */
                                <div className="w-full h-full flex items-center justify-center bg-bronze/10 animate-pulse">
                                  {isVideo
                                    ? <Video className="h-6 w-6 text-bronze/30" />
                                    : <ImageIcon className="h-6 w-6 text-bronze/30" />
                                  }
                                </div>
                              )}
                              {/* Download overlay on hover */}
                              <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors flex items-center justify-center">
                                <Download className="h-4 w-4 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
                              </div>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}

            {/* Docs Tab */}
            {activeTab === "docs" && (
              docItems.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
                  <File className="h-8 w-8 mb-2 opacity-30" />
                  <p className="text-xs">No documents shared yet</p>
                </div>
              ) : (
                <div className="space-y-3 px-1">
                  {groupByMonth(docItems).map((group) => (
                    <div key={group.label}>
                      <p className="text-[10px] font-bold text-muted-foreground tracking-wider mb-2">
                        {group.label}
                      </p>
                      <div className="space-y-1.5">
                        {group.items.map((item) => {
                          const isInvoice = item.message_type === "invoice";
                          const isContract = item.message_type === "contract";
                          const Icon = isInvoice ? Receipt : isContract ? FileSignature : File;

                          return (
                            <button
                              key={item.id}
                              onClick={() => {
                                if (item.file_url) downloadFile(item.file_url, item.file_name || "file");
                              }}
                              className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 transition-colors text-left"
                            >
                              <div className="h-10 w-10 rounded-lg bg-bronze/10 flex items-center justify-center flex-shrink-0">
                                <Icon className="h-5 w-5 text-bronze" />
                              </div>
                              <div className="flex-1 min-w-0">
                                <p className="text-xs font-medium truncate">
                                  {isInvoice ? "Invoice" : isContract ? "Contract" : item.file_name || "File"}
                                </p>
                                <p className="text-[10px] text-muted-foreground">
                                  {item.file_size ? formatFileSize(item.file_size) + " • " : ""}
                                  {format(new Date(item.created_at), "MMM d, yyyy")}
                                </p>
                              </div>
                              {item.file_url && (
                                <Download className="h-4 w-4 text-muted-foreground flex-shrink-0" />
                              )}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}

            {/* Links Tab */}
            {activeTab === "links" && (
              linkItems.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
                  <Link2 className="h-8 w-8 mb-2 opacity-30" />
                  <p className="text-xs">No links shared yet</p>
                </div>
              ) : (
                <div className="space-y-3 px-1">
                  {groupByMonth(linkItems).map((group) => (
                    <div key={group.label}>
                      <p className="text-[10px] font-bold text-muted-foreground tracking-wider mb-2">
                        {group.label}
                      </p>
                      <div className="space-y-1.5">
                        {group.items.map((item) => {
                          let displayUrl = item.url;
                          try {
                            const parsed = new URL(item.url);
                            displayUrl = parsed.hostname + (parsed.pathname !== "/" ? parsed.pathname : "");
                          } catch {}

                          return (
                            <a
                              key={item.id}
                              href={item.url}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 transition-colors"
                            >
                              <div className="h-10 w-10 rounded-lg bg-bronze/10 flex items-center justify-center flex-shrink-0">
                                <Link2 className="h-5 w-5 text-bronze" />
                              </div>
                              <div className="flex-1 min-w-0">
                                <p className="text-xs font-medium truncate text-foreground">{displayUrl}</p>
                                <p className="text-[10px] text-muted-foreground">
                                  {format(new Date(item.created_at), "MMM d, yyyy")}
                                </p>
                              </div>
                              <ExternalLink className="h-4 w-4 text-muted-foreground flex-shrink-0" />
                            </a>
                          );
                        })}
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}
          </>
        )}
      </ScrollArea>
    </div>
  );
};

