34	// --- WebAuthn Helpers ---
35	const BIOMETRIC_CRED_KEY = "crevia_webauthn_cred_id";
36	const BIOMETRIC_ENABLED_KEY = "crevia_biometric_enabled";
37	
38	function bufferToBase64url(buffer: ArrayBuffer): string {
39	  const bytes = new Uint8Array(buffer);
40	  let str = "";
41	  for (const b of bytes) str += String.fromCharCode(b);
42	  return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
43	}
44	
45	function base64urlToBuffer(base64url: string): ArrayBuffer {
46	  const base64 = base64url.replace(/-/g, "+").replace(/_/g, "/");
47	  const pad = base64.length % 4 === 0 ? "" : "=".repeat(4 - (base64.length % 4));
48	  const binary = atob(base64 + pad);
49	  const bytes = new Uint8Array(binary.length);
50	  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
51	  return bytes.buffer;
52	}
53	
54	function isWebAuthnSupported(): boolean {
55	  return !!(window.PublicKeyCredential && navigator.credentials);
56	}
57	
58	function isInIframe(): boolean {
59	  try { return window.self !== window.top; } catch { return true; }
60	}
61	
62	async function isPlatformAuthAvailable(): Promise<boolean> {
63	  if (!isWebAuthnSupported()) return false;
64	  if (isInIframe()) return false;
65	  try {
66	    return await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
67	  } catch {
68	    return false;
69	  }
70	}
71	
72	async function registerBiometric(userId: string): Promise<string | null> {
73	  const challenge = crypto.getRandomValues(new Uint8Array(32));
74	  const userIdBytes = new TextEncoder().encode(userId);
75	
76	  const credential = (await navigator.credentials.create({
77	    publicKey: {
78	      challenge,
79	      rp: { name: "Crevia", id: window.location.hostname },
80	      user: {
81	        id: userIdBytes,
82	        name: userId,
83	        displayName: "Crevia User",
84	      },
85	      pubKeyCredParams: [
86	        { alg: -7, type: "public-key" },   // ES256
87	        { alg: -257, type: "public-key" },  // RS256
88	      ],
89	      authenticatorSelection: {
90	        authenticatorAttachment: "platform",
91	        userVerification: "required",
92	        residentKey: "preferred",
93	      },
94	      timeout: 60000,
95	      attestation: "none",
96	    },
97	  })) as PublicKeyCredential | null;
98	
99	  if (!credential) return null;
100	  const credId = bufferToBase64url(credential.rawId);
101	  localStorage.setItem(BIOMETRIC_CRED_KEY, credId);
102	  localStorage.setItem(BIOMETRIC_ENABLED_KEY, "true");
103	  return credId;
104	}
105	
106	async function verifyBiometric(): Promise<boolean> {
107	  const storedCredId = localStorage.getItem(BIOMETRIC_CRED_KEY);
108	  if (!storedCredId) return false;
109	
110	  const challenge = crypto.getRandomValues(new Uint8Array(32));
111	  try {
112	    const assertion = (await navigator.credentials.get({
113	      publicKey: {
114	        challenge,
115	        allowCredentials: [
116	          {
117	            id: base64urlToBuffer(storedCredId),
118	            type: "public-key",
119	            transports: ["internal"],
120	          },
121	        ],
122	        userVerification: "required",
123	        timeout: 60000,
124	      },
125	    })) as PublicKeyCredential | null;
126	    return !!assertion;
127	  } catch {
128	    return false;
129	  }
130	}
131	
132	function removeBiometric() {
133	  localStorage.removeItem(BIOMETRIC_CRED_KEY);
134	  localStorage.removeItem(BIOMETRIC_ENABLED_KEY);
135	}
136	// --- End WebAuthn Helpers ---
137	
138	const SecurityTab = () => {
139	  const { toast } = useToast();
140	  const { t } = useLanguage();
141	
142	  // Password change state
143	  const [showChangePassword, setShowChangePassword] = useState(false);
144	  const [currentPassword, setCurrentPassword] = useState("");
145	  const [newPassword, setNewPassword] = useState("");
146	  const [confirmPassword, setConfirmPassword] = useState("");
147	  const [showNew, setShowNew] = useState(false);
148	  const [showConfirm, setShowConfirm] = useState(false);
149	  const [changingPassword, setChangingPassword] = useState(false);
150	
151	  // 2FA / biometric toggles
152	  const [twoFactorEnabled, setTwoFactorEnabled] = useState(false);
153	  const [biometricEnabled, setBiometricEnabled] = useState(
154	    () => localStorage.getItem(BIOMETRIC_ENABLED_KEY) === "true"
155	  );
156	  const [biometricAvailable, setBiometricAvailable] = useState(false);
157	  const [biometricBusy, setBiometricBusy] = useState(false);
158	  const [loginAlertsEnabled, setLoginAlertsEnabled] = useState(true);
159	
160	  // Sign out all devices dialog
161	  const [showSignOutAll, setShowSignOutAll] = useState(false);
162	  const [signingOut, setSigningOut] = useState(false);
163	
164	  // Check biometric availability on mount
165	  useEffect(() => {
166	    isPlatformAuthAvailable().then(setBiometricAvailable);
167	  }, []);
168	
169	  const handleBiometricToggle = useCallback(async (checked: boolean) => {
170	    setBiometricBusy(true);
171	    try {
172	      if (checked) {
173	        if (!biometricAvailable) {
174	          toast({
175	            title: "Not supported",
176	            description: "Your device or browser doesn't support biometric authentication.",
177	            variant: "destructive",
178	          });
179	          return;
180	        }
181	
182	        const { data: { session } } = await supabase.auth.getSession();
183	        if (!session) {
184	          toast({ title: "Not logged in", variant: "destructive" });
185	          return;
186	        }
187	
188	        const credId = await registerBiometric(session.user.id);
189	        if (!credId) {
190	          toast({
191	            title: "Registration cancelled",
192	            description: "Biometric registration was cancelled or failed.",
193	            variant: "destructive",
194	          });
195	          return;
196	        }
197	
198	        setBiometricEnabled(true);
199	        toast({
200	          title: "Biometric login enabled",
201	          description: "You can now use fingerprint or Face ID to unlock Crevia.",
202	        });
203	      } else {
204	        // Verify identity before disabling
205	        const verified = await verifyBiometric();
206	        if (!verified) {
207	          toast({
208	            title: "Verification failed",
209	            description: "Biometric verification is required to disable this feature.",
210	            variant: "destructive",
211	          });
212	          return;
213	        }
214	        removeBiometric();
215	        setBiometricEnabled(false);
216	        toast({
217	          title: "Biometric login disabled",
218	          description: "Biometric credentials have been removed from this device.",
219	        });
220	      }
221	    } catch (err: any) {
222	      console.error("Biometric error:", err);
223	      toast({
224	        title: "Biometric error",
225	        description: err?.message || "Something went wrong with biometric authentication.",
226	        variant: "destructive",
227	      });
228	    } finally {
229	      setBiometricBusy(false);
230	    }
231	  }, [biometricAvailable, toast]);
232	
233	  // Password strength checker
234	  const getPasswordStrength = (pw: string) => {
235	    let score = 0;
236	    if (pw.length >= 8) score++;
237	    if (/[A-Z]/.test(pw)) score++;
238	    if (/[a-z]/.test(pw)) score++;
239	    if (/[0-9]/.test(pw)) score++;
240	    if (/[^A-Za-z0-9]/.test(pw)) score++;
241	    if (score <= 2) return { label: "Weak", color: "text-destructive", bg: "bg-destructive" };
242	    if (score <= 3) return { label: "Fair", color: "text-yellow-500", bg: "bg-yellow-500" };
243	    if (score <= 4) return { label: "Strong", color: "text-emerald-500", bg: "bg-emerald-500" };
244	    return { label: "Very Strong", color: "text-emerald-600", bg: "bg-emerald-600" };
245	  };
246	
247	  const passwordChecks = [
248	    { label: "At least 8 characters", met: newPassword.length >= 8 },
249	    { label: "Uppercase letter", met: /[A-Z]/.test(newPassword) },
250	    { label: "Lowercase letter", met: /[a-z]/.test(newPassword) },
251	    { label: "Number", met: /[0-9]/.test(newPassword) },
252	    { label: "Special character (!@#$...)", met: /[^A-Za-z0-9]/.test(newPassword) },
253	  ];
254	
